//#region src/main/ai/OllamaProvider.ts
var OllamaProvider = class {
	id = "ollama";
	name = "Ollama (Local)";
	baseUrl;
	model;
	constructor(baseUrl = "http://localhost:11434", model = "llama3") {
		this.baseUrl = baseUrl;
		this.model = model;
	}
	async chat(messages) {
		const response = await fetch(`${this.baseUrl}/api/chat`, {
			method: "POST",
			headers: { "Content-Type": "application/json" },
			body: JSON.stringify({
				model: this.model,
				messages,
				stream: false
			})
		});
		if (!response.ok) throw new Error(`Ollama API error: ${response.statusText}`);
		return {
			content: (await response.json()).message.content,
			modelUsed: this.model
		};
	}
	async explainCode(code) {
		return (await this.chat([{
			role: "system",
			content: "You are an expert Android developer. Explain the following code concisely."
		}, {
			role: "user",
			content: code
		}])).content;
	}
	async analyzeManifest(xml) {
		return (await this.chat([{
			role: "system",
			content: "You are an Android security expert. Analyze this AndroidManifest.xml for potential security vulnerabilities, misconfigurations, or unnecessary permissions."
		}, {
			role: "user",
			content: xml
		}])).content;
	}
	async summarize(text) {
		return (await this.chat([{
			role: "system",
			content: "Provide a brief summary of the following text."
		}, {
			role: "user",
			content: text
		}])).content;
	}
};
//#endregion
//#region src/main/ai/OpenAIProvider.ts
var OpenAIProvider = class {
	id = "openai";
	name = "OpenAI";
	apiKey;
	model;
	constructor(apiKey, model = "gpt-4o") {
		this.apiKey = apiKey;
		this.model = model;
	}
	async chat(messages) {
		if (!this.apiKey) throw new Error("OpenAI API Key is not configured.");
		const response = await fetch("https://api.openai.com/v1/chat/completions", {
			method: "POST",
			headers: {
				"Content-Type": "application/json",
				"Authorization": `Bearer ${this.apiKey}`
			},
			body: JSON.stringify({
				model: this.model,
				messages
			})
		});
		if (!response.ok) {
			const errBody = await response.text();
			throw new Error(`OpenAI API error (${response.status}): ${errBody}`);
		}
		const data = await response.json();
		return {
			content: data.choices[0].message.content,
			modelUsed: this.model,
			tokensUsed: data.usage?.total_tokens
		};
	}
	async explainCode(code) {
		return (await this.chat([{
			role: "system",
			content: "You are an expert Android developer. Explain the following code concisely."
		}, {
			role: "user",
			content: code
		}])).content;
	}
	async analyzeManifest(xml) {
		return (await this.chat([{
			role: "system",
			content: "You are an Android security expert. Analyze this AndroidManifest.xml for potential security vulnerabilities, misconfigurations, or unnecessary permissions."
		}, {
			role: "user",
			content: xml
		}])).content;
	}
	async summarize(text) {
		return (await this.chat([{
			role: "system",
			content: "Provide a brief summary of the following text."
		}, {
			role: "user",
			content: text
		}])).content;
	}
};
