//#region src/main/ai/GeminiProvider.ts
var GeminiProvider = class {
	id = "gemini";
	name = "Google Gemini";
	apiKey;
	model;
	constructor(apiKey, model = "gemini-1.5-pro") {
		this.apiKey = apiKey;
		this.model = model;
	}
	async chat(messages) {
		if (!this.apiKey) throw new Error("Gemini API Key is not configured.");
		let systemPrompt = "";
		const geminiContents = messages.map((msg) => {
			if (msg.role === "system") {
				systemPrompt += msg.content + "\n";
				return null;
			}
			return {
				role: msg.role === "assistant" ? "model" : "user",
				parts: [{ text: msg.content }]
			};
		}).filter(Boolean);
		if (systemPrompt && geminiContents.length > 0) geminiContents[0].parts[0].text = `[System Instruction: ${systemPrompt}]\n\n${geminiContents[0].parts[0].text}`;
		const response = await fetch(`https://generativelanguage.googleapis.com/v1beta/models/${this.model}:generateContent?key=${this.apiKey}`, {
			method: "POST",
			headers: { "Content-Type": "application/json" },
			body: JSON.stringify({ contents: geminiContents })
		});
		if (!response.ok) {
			const errBody = await response.text();
			throw new Error(`Gemini API error (${response.status}): ${errBody}`);
		}
		return {
			content: (await response.json()).candidates?.[0]?.content?.parts?.[0]?.text || "",
			modelUsed: this.model
		};
	}
	async explainCode(code) {
		return (await this.chat([{
			role: "system",
			content: "You are an expert Android developer. Explain the following code concisely."
		}, {
			role: "user",
			content: code
		}])).content;
	}
	async analyzeManifest(xml) {
		return (await this.chat([{
			role: "system",
			content: "You are an Android security expert. Analyze this AndroidManifest.xml for potential security vulnerabilities, misconfigurations, or unnecessary permissions."
		}, {
			role: "user",
			content: xml
		}])).content;
	}
	async summarize(text) {
		return (await this.chat([{
			role: "system",
			content: "Provide a brief summary of the following text."
		}, {
			role: "user",
			content: text
		}])).content;
	}
};
