//#region src/main/ai/AIChatHistory.ts
var AIChatHistory = class {
	db = null;
	initialize(workspaceRoot) {
		const aiDir = path.join(workspaceRoot, ".ai");
		if (!fs.existsSync(aiDir)) fs.mkdirSync(aiDir, { recursive: true });
		const dbPath = path.join(aiDir, "history.db");
		this.db = new better_sqlite3.default(dbPath);
		this.db.exec(`
            CREATE TABLE IF NOT EXISTS chat_history (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                role TEXT NOT NULL,
                content TEXT NOT NULL,
                provider TEXT,
                timestamp DATETIME DEFAULT CURRENT_TIMESTAMP
            );
        `);
	}
	addMessage(role, content, provider) {
		if (!this.db) return;
		this.db.prepare("INSERT INTO chat_history (role, content, provider) VALUES (?, ?, ?)").run(role, content, provider || null);
	}
	getHistory(limit = 50) {
		if (!this.db) return [];
		return this.db.prepare("SELECT * FROM chat_history ORDER BY timestamp ASC LIMIT ?").all(limit);
	}
	clearHistory() {
		if (!this.db) return;
		this.db.exec("DELETE FROM chat_history");
	}
};
var chatHistory = new AIChatHistory();
//#endregion
//#region src/main/ai/AIContextManager.ts
var AIContextManager = class {
	maxChars = 8e3 * 4;
	buildContextPrompt(context) {
		let prompt = "Context Information:\n";
		if (context.workspaceRoot) prompt += `- Workspace Root: ${context.workspaceRoot}\n`;
		if (context.activeFilePath) {
			prompt += `- Active File: ${context.activeFilePath}\n`;
			try {
				if (fs.statSync(context.activeFilePath).size > this.maxChars) {
					const buffer = Buffer.alloc(this.maxChars);
					const fd = fs.openSync(context.activeFilePath, "r");
					fs.readSync(fd, buffer, 0, this.maxChars, 0);
					fs.closeSync(fd);
					prompt += `- Active File Content (Truncated):\n\`\`\`\n${buffer.toString("utf8")}...\n\`\`\`\n`;
				} else {
					const content = fs.readFileSync(context.activeFilePath, "utf8");
					prompt += `- Active File Content:\n\`\`\`\n${content}\n\`\`\`\n`;
				}
			} catch (err) {
				prompt += `- Active File Content: [Error reading file: ${err.message}]\n`;
			}
		}
		if (context.selectedText) prompt += `- Selected Text:\n\`\`\`\n${context.selectedText}\n\`\`\`\n`;
		prompt += "\nEnd of Context Information.\n";
		return prompt;
	}
};
var aiContextManager = new AIContextManager();
//#endregion
//#region src/main/ai/AIManager.ts
var AIManager = class {
	activeProvider = null;
	providers = {};
	constructor() {
		this.providers["ollama"] = new OllamaProvider();
		this.providers["openai"] = new OpenAIProvider(process.env.OPENAI_API_KEY || "");
		this.providers["gemini"] = new GeminiProvider(process.env.GEMINI_API_KEY || "");
		this.activeProvider = this.providers["ollama"];
	}
	setProvider(providerId, apiKey) {
		if (!this.providers[providerId]) throw new Error(`Provider ${providerId} not found`);
		if (apiKey) {
			if (providerId === "openai") this.providers["openai"] = new OpenAIProvider(apiKey);
			else if (providerId === "gemini") this.providers["gemini"] = new GeminiProvider(apiKey);
		}
		this.activeProvider = this.providers[providerId];
	}
	getProvider() {
		if (!this.activeProvider) throw new Error("No active AI provider");
		return this.activeProvider;
	}
	registerIPC() {
		commandBus.register("ai.initWorkspace", async (workspaceRoot) => {
			chatHistory.initialize(workspaceRoot);
			return true;
		});
		commandBus.register("ai.chat", async (args) => {
			const provider = this.getProvider();
			const messages = [...args.messages];
			if (args.context) {
				const contextPrompt = aiContextManager.buildContextPrompt(args.context);
				const lastUserMsgIndex = messages.findLastIndex((m) => m.role === "user");
				if (lastUserMsgIndex !== -1) messages[lastUserMsgIndex].content = `${contextPrompt}\n\nUser Query: ${messages[lastUserMsgIndex].content}`;
			}
			const lastOriginalMsg = args.messages[args.messages.length - 1];
			if (lastOriginalMsg && lastOriginalMsg.role === "user") chatHistory.addMessage("user", lastOriginalMsg.content);
			const response = await provider.chat(messages);
			chatHistory.addMessage("assistant", response.content, provider.id);
			return response;
		});
		commandBus.register("ai.explainCode", async (code) => {
			return await this.getProvider().explainCode(code);
		});
		commandBus.register("ai.analyzeManifest", async (xml) => {
			return await this.getProvider().analyzeManifest(xml);
		});
		commandBus.register("ai.getHistory", async () => {
			return chatHistory.getHistory();
		});
	}
};
var aiManager = new AIManager();
//#endregion
//#region src/main/plugins/PluginManager.ts
var PluginManager = class {
	pluginsDir = null;
	availablePlugins = {};
	enabledPlugins = {};
	workers = {};
	initialize(workspaceRoot) {
		this.pluginsDir = path.join(workspaceRoot, ".plugins");
		if (!fs.existsSync(this.pluginsDir)) fs.mkdirSync(this.pluginsDir, { recursive: true });
		this.scanPlugins();
	}
	scanPlugins() {
		if (!this.pluginsDir) return;
		this.availablePlugins = {};
		const entries = fs.readdirSync(this.pluginsDir, { withFileTypes: true });
		for (const entry of entries) if (entry.isDirectory()) {
			const manifestPath = path.join(this.pluginsDir, entry.name, "plugin.json");
			if (fs.existsSync(manifestPath)) try {
				const manifest = JSON.parse(fs.readFileSync(manifestPath, "utf8"));
				this.availablePlugins[manifest.id] = manifest;
			} catch (e) {
				console.error(`Failed to load plugin manifest at ${manifestPath}`, e);
			}
		}
	}
	getPlugins() {
		return Object.values(this.availablePlugins).map((manifest) => ({
			...manifest,
			enabled: !!this.enabledPlugins[manifest.id]
		}));
	}
	enablePlugin(id) {
		const manifest = this.availablePlugins[id];
		if (!manifest) throw new Error(`Plugin ${id} not found`);
		this.enabledPlugins[id] = true;
		if (manifest.main) {
			const mainPath = path.join(this.pluginsDir, id, manifest.main);
			if (fs.existsSync(mainPath)) try {
				const worker = new worker_threads.Worker(mainPath);
				this.workers[id] = worker;
				worker.on("message", (msg) => {
					console.log(`[Plugin:${id}]`, msg);
				});
				worker.on("error", (err) => {
					console.error(`[Plugin:${id}] Error:`, err);
				});
			} catch (e) {
				console.error(`Failed to launch plugin worker ${id}`, e);
			}
		}
		return { success: true };
	}
	disablePlugin(id) {
		this.enabledPlugins[id] = false;
		if (this.workers[id]) {
			this.workers[id].terminate();
			delete this.workers[id];
		}
		return { success: true };
	}
	registerIPC() {
		commandBus.register("plugins.init", async (workspaceRoot) => {
			this.initialize(workspaceRoot);
			return { success: true };
		});
		commandBus.register("plugins.list", async () => {
			this.scanPlugins();
			return {
				success: true,
				data: this.getPlugins()
			};
		});
		commandBus.register("plugins.enable", async (id) => {
			try {
				return this.enablePlugin(id);
			} catch (e) {
				return {
					success: false,
					error: e.message
				};
			}
		});
		commandBus.register("plugins.disable", async (id) => {
			try {
				return this.disablePlugin(id);
			} catch (e) {
				return {
					success: false,
					error: e.message
				};
			}
		});
	}
};
var pluginManager = new PluginManager();
